local G = DYCLegendary local require = G.DYCModRequire local dlc = G.dlc local spells = require( "dyc_spells" ) local Round = function(num) return math.floor(num + 0.5) end local Clamp = function(num, min, max) return math.min(math.max(num, min), max) end local assets = {Asset( "ATLAS" , "images/inventoryimages/dyccryomachete.xml" ), Asset( "IMAGE" , "images/inventoryimages/dyccryomachete.tex" ), Asset( "ATLAS" , "images/inventoryimages/dyc_halberd.xml" ), Asset( "IMAGE" , "images/inventoryimages/dyc_halberd.tex" ), Asset( "ANIM" , "anim/dyc_cryomachete.zip" ), Asset( "ANIM" , "anim/swap_dyc_cryomachete.zip" ), Asset( "ANIM" , "anim/dyc_halberd.zip" ), Asset( "ANIM" , "anim/swap_dyc_halberd.zip" ), } local function onwork(inst, worker, target) local clb = inst.feature_CryoLaserBeam_work if clb then if not inst.spell_laserbeam_cold_work then inst.spell_laserbeam_cold_work = LaserBeam({caster = worker, damage = clb.damage, range = clb.range, speed = clb.speed, damagetype = "ice" , lasercolor = "blue" , coldness = clb.coldness}) end if math.random() <= clb.chance then inst.spell_laserbeam_cold_work:CastToTarget(target) end end end local function OnEquip(inst, owner) if inst.Light then inst.Light:Enable(true) end owner.AnimState:OverrideSymbol( "swap_object" , inst.swap_build, inst.swap_symbol) owner.SoundEmitter:PlaySound( "dontstarve/wilson/equip_item_gold" ) owner.AnimState:Show( "ARM_carry" ) owner.AnimState:Hide( "ARM_normal" ) if owner.components.health then local health = owner.components.health health.fire_damage_scale = health.fire_damage_scale - (inst.feature_FireResistance or 0x0) end end local function OnUnequip(inst, owner) if inst.Light then inst.Light:Enable(true) end owner.AnimState:Hide( "ARM_carry" ) owner.AnimState:Show( "ARM_normal" ) if owner.components.health then local health = owner.components.health health.fire_damage_scale = health.fire_damage_scale + (inst.feature_FireResistance or 0x0) end if owner.dyc_cryolaserbeam_onworkfn then owner:RemoveEventCallback( "working" , owner.dyc_cryolaserbeam_onworkfn) owner.dyc_cryolaserbeam_onworkfn = nil end end local function OnPutInInv(inst, owner) if inst.Light then inst.Light:Enable(true) end end local function onattack(inst, attacker, target) local finiteuses = inst.components.finiteuses local uses = finiteuses and finiteuses:GetUses() or 0x0 if finiteuses and uses and uses > 0x0 then finiteuses:Use(math.min(0.4, uses)) end end local function OnStateChange(inst) local finiteuses = inst.components.finiteuses local uses = finiteuses and finiteuses:GetUses() local q = inst:GetQuality() if uses > 0x0 then inst.components.weapon:SetDamage(inst.damage_Attack) if inst.weapon_Type == "machete" then inst.components.tool:SetAction(ACTIONS.CHOP, 0x2) inst.components.tool:SetAction(ACTIONS.MINE, 0x2) inst.components.tool:SetAction(ACTIONS.HAMMER, 0x1) if dlc >= 0x2 then inst.components.tool:SetAction(ACTIONS.HACK, 0x2) end if inst.components.finiteuses then inst.components.finiteuses:SetConsumption(ACTIONS.CHOP, 0.2) inst.components.finiteuses:SetConsumption(ACTIONS.MINE, 0.2) inst.components.finiteuses:SetConsumption(ACTIONS.HAMMER, 0.2) if dlc >= 0x2 then inst.components.finiteuses:SetConsumption(ACTIONS.HACK, 0.2) end end elseif inst.weapon_Type == "halberd" then inst.components.tool:SetAction(ACTIONS.CHOP, Clamp(Round((q - 0x1) * 0x4 + 0x4), 0x1, 0xf)) if inst.components.finiteuses then inst.components.finiteuses:SetConsumption(ACTIONS.CHOP, 0.2) end end else inst.components.weapon:SetDamage(inst.damage_UseUp) if inst.weapon_Type == "machete" then inst.components.tool:SetAction(ACTIONS.CHOP, 0x0) inst.components.tool:SetAction(ACTIONS.MINE, 0x0) inst.components.tool:SetAction(ACTIONS.HAMMER, 0x1) if dlc >= 0x2 then inst.components.tool:SetAction(ACTIONS.HACK, 0x1) end if inst.components.finiteuses then inst.components.finiteuses:SetConsumption(ACTIONS.CHOP, 0x0) inst.components.finiteuses:SetConsumption(ACTIONS.MINE, 0x0) inst.components.finiteuses:SetConsumption(ACTIONS.HAMMER, 0x0) if dlc >= 0x2 then inst.components.finiteuses:SetConsumption(ACTIONS.HACK, 0x0) end end elseif inst.weapon_Type == "halberd" then inst.components.tool:SetAction(ACTIONS.CHOP, 0x1) if inst.components.finiteuses then inst.components.finiteuses:SetConsumption(ACTIONS.CHOP, 0x0) end end end end local function OnFinished(inst) local brokentool = SpawnPrefab( "brokentool" ) brokentool.Transform:SetPosition(inst.Transform:GetWorldPosition()) OnStateChange(inst) end local function fn() local inst = CreateEntity() local trans = inst.entity:AddTransform() local anim = inst.entity:AddAnimState() inst.entity:AddSoundEmitter() MakeInventoryPhysics(inst) if dlc >= 0x2 then MakeInventoryFloatable(inst, "idle_water" , "idle" ) end inst.damage_UseUp = 0x11 inst.damage_Attack = 0x1e inst:AddTag( "sharp" ) inst:AddComponent( "inspectable" ) inst:AddComponent( "inventoryitem" ) inst:AddComponent( "weapon" ) inst:AddComponent( "tool" ) inst:AddComponent( "equippable" ) inst.components.equippable:SetOnEquip(OnEquip) inst.components.equippable:SetOnUnequip(OnUnequip) inst.components.weapon.attackwear = 0x0 inst.components.weapon.onattack = onattack inst.components.tool:MakeNoBrokeAnim(true) inst.components.inventoryitem:SetOnPutInInventoryFn(OnPutInInv) inst:AddComponent( "finiteuses" ) inst.components.finiteuses:SetMaxUses(0x96) inst.components.finiteuses:SetUses(0x96) inst.components.finiteuses:SetOnFinished(OnFinished) inst:AddComponent( "repairable" ) inst.components.repairable.repairmaterial = "gem" inst.components.repairable.announcecanfix = false inst.components.repairable.onrepaired = function() OnStateChange(inst) end inst.OnQualityChange = function(inst, q) OnStateChange(inst) end inst.OnEnchantmentChange = function(inst) OnStateChange(inst) end return inst end local function dycmachete() local inst = fn() local trans = inst.Transform local anim = inst.AnimState anim:SetBank( "dyc_cryomachete" ) anim:SetBuild( "dyc_cryomachete" ) anim:PlayAnimation( "idle" ) inst.swap_build = "swap_dyc_cryomachete" inst.swap_symbol = "swap_machete" inst.components.inventoryitem.atlasname = "images/inventoryimages/dyccryomachete.xml" inst.components.inventoryitem.imagename = "dyccryomachete" inst:AddTag( "dyc_gem_blue" ) inst.scrapProduct = "dyc_gem_blue" inst.entity:AddLight() inst.Light:SetColour(0x32 / 0xff, 0xb4 / 0xff, 0xff / 0xff) inst.Light:SetFalloff(0.3) inst.Light:SetIntensity(0.05) inst.Light:SetRadius(5.5) inst.Light:Enable(true) inst.weapon_Type = "machete" inst.damage_Attack = 0x22 inst.components.weapon:SetDamage(inst.damage_Attack) inst.components.equippable:SetFollowingFXs({{prefab = "dyc_p_frost_smoke" , follow = "swap_object" , scale = 0.6, x = 0x0, y = 0x0, z = 0x0,}, {prefab = "dyc_p_frost_smoke" , follow = "swap_object" , scale = 0.65, x = 0xa, y = - 0x32, z = 0x0,}, {prefab = "dyc_p_frost_smoke" , follow = "swap_object" , scale = 0.7, x = 0x14, y = - 0x64, z = 0x0,}, {prefab = "dyc_p_frost_smoke" , follow = "swap_object" , scale = 0.75, x = 0x1e, y = - 0x96, z = 0x0,}, {prefab = "dyc_p_frost_smoke" , follow = "swap_object" , scale = 0.8, x = 0x28, y = - 0xc8, z = 0x0,},}) inst:SetRandomQuality() inst:AddEnchantment( "laserbeam_cold" ) return inst end local function dychalberd() local inst = fn() local trans = inst.Transform local anim = inst.AnimState anim:SetBank( "dyc_halberd" ) anim:SetBuild( "dyc_halberd" ) anim:PlayAnimation( "idle" ) inst.swap_build = "swap_dyc_halberd" inst.swap_symbol = "swap_halberd" inst.components.inventoryitem.atlasname = "images/inventoryimages/dyc_halberd.xml" inst.components.inventoryitem.imagename = "dyc_halberd" inst:AddTag( "halberd" ) inst:AddTag( "dyc_gem_orange" ) inst.scrapProduct = "dyc_gem_orange" inst.weapon_Type = "halberd" inst.damage_Attack = 0x33 inst.components.weapon:SetDamage(inst.damage_Attack) inst.feature_FireResistance = 0x1 inst.components.equippable:SetFollowingFXs({{prefab = "dyc_p_glow_red" , follow = "swap_object" , scale = 0.5, x = 0x0, y = - 0x5a, z = 0x0,}, {prefab = "dyc_p_shockwave_red" , follow = "swap_object" , scale = 0x2, x = 0x0, y = - 0x5a, z = 0x0, lifespan = 1.1, delay = 0.6},}) inst:SetRandomQuality() inst:AddEnchantment( "firefissure" ) return inst end return Prefab( "common/inventory/dyc_machete" , dycmachete, assets), Prefab( "common/inventory/dyc_halberd" , dychalberd, assets) 